type store struct {
	mu sync.RWMutex

	users    map[string]*User
	orders   map[string]*Order
	payments map[string]*Payment

	userSeq    int64
	orderSeq   int64
	paymentSeq int64
}

func newStore() *store {
	return &store{
		users:    make(map[string]*User),
		orders:   make(map[string]*Order),
		payments: make(map[string]*Payment),
	}
}

func (s *store) nextID(prefix string, seq *int64) string {
	*seq++
	return fmt.Sprintf("%s_%d", prefix, *seq)
}

func nowUnix() int64 { return time.Now().Unix() }

func paginateTokenToOffset(token string) (int, error) {
	if token == "" {
		return 0, nil
	}
	n, err := strconv.Atoi(token)
	if err != nil || n < 0 {
		return 0, errors.New("invalid page token")
	}
	return n, nil
}

func offsetToPageToken(offset int) string {
	if offset <= 0 {
		return ""
	}
	return strconv.Itoa(offset)
}

type userService struct{ st *store }

func (u *userService) CreateUser(ctx context.Context, req *CreateUserRequest) (*CreateUserResponse, error) {
	if strings.TrimSpace(req.Name) == "" {
		return nil, status.Error(codes.InvalidArgument, "name is required")
	}
	if strings.TrimSpace(req.Email) == "" {
		return nil, status.Error(codes.InvalidArgument, "email is required")
	}
	u.st.mu.Lock()
	defer u.st.mu.Unlock()

	id := u.st.nextID("usr", &u.st.userSeq)
	user := &User{Id: id, Name: req.Name, Email: req.Email, CreatedAt: nowUnix()}
	u.st.users[id] = user
	return &CreateUserResponse{User: cloneUser(user)}, nil
}

func (u *userService) GetUser(ctx context.Context, req *GetUserRequest) (*GetUserResponse, error) {
	if strings.TrimSpace(req.Id) == "" {
		return nil, status.Error(codes.InvalidArgument, "id is required")
	}
	u.st.mu.RLock()
	defer u.st.mu.RUnlock()

	user, ok := u.st.users[req.Id]
	if !ok {
		return nil, status.Error(codes.NotFound, "user not found")
	}
	return &GetUserResponse{User: cloneUser(user)}, nil
}

func (u *userService) ListUsers(ctx context.Context, req *ListUsersRequest) (*ListUsersResponse, error) {
	pageSize := int(req.PageSize)
	if pageSize <= 0 {
		pageSize = 50
	}
	if pageSize > 500 {
		pageSize = 500
	}

	offset, err := paginateTokenToOffset(req.PageToken)
	if err != nil {
		return nil, status.Error(codes.InvalidArgument, err.Error())
	}

	u.st.mu.RLock()
	defer u.st.mu.RUnlock()

	all := make([]*User, 0, len(u.st.users))
	for _, v := range u.st.users {
		all = append(all, cloneUser(v))
	}

	if offset >= len(all) {
		return &ListUsersResponse{Users: []*User{}, NextPageToken: ""}, nil
	}

	end := offset + pageSize
	if end > len(all) {
		end = len(all)
	}
	next := ""
	if end < len(all) {
		next = offsetToPageToken(end)
	}

	return &ListUsersResponse{Users: all[offset:end], NextPageToken: next}, nil
}

func (u *userService) UpdateUser(ctx context.Context, req *UpdateUserRequest) (*UpdateUserResponse, error) {
	if strings.TrimSpace(req.Id) == "" {
		return nil, status.Error(codes.InvalidArgument, "id is required")
	}
	u.st.mu.Lock()
	defer u.st.mu.Unlock()

	user, ok := u.st.users[req.Id]
	if !ok {
		return nil, status.Error(codes.NotFound, "user not found")
	}
	if strings.TrimSpace(req.Name) != "" {
		user.Name = req.Name
	}
	if strings.TrimSpace(req.Email) != "" {
		user.Email = req.Email
	}
	return &UpdateUserResponse{User: cloneUser(user)}, nil
}

func (u *userService) DeleteUser(ctx context.Context, req *DeleteUserRequest) (*DeleteUserResponse, error) {
	if strings.TrimSpace(req.Id) == "" {
		return nil, status.Error(codes.InvalidArgument, "id is required")
	}
	u.st.mu.Lock()
	defer u.st.mu.Unlock()

	if _, ok := u.st.users[req.Id]; !ok {
		return nil, status.Error(codes.NotFound, "user not found")
	}
	delete(u.st.users, req.Id)
	return &DeleteUserResponse{Deleted: true}, nil
}

type orderService struct{ st *store }

func (o *orderService) CreateOrder(ctx context.Context, req *CreateOrderRequest) (*CreateOrderResponse, error) {
	if strings.TrimSpace(req.UserId) == "" {
		return nil, status.Error(codes.InvalidArgument, "user_id is required")
	}
	if len(req.Items) == 0 {
		return nil, status.Error(codes.InvalidArgument, "items is required")
	}
	var total int64
	for _, it := range req.Items {
		if it == nil || strings.TrimSpace(it.Sku) == "" || it.Quantity <= 0 || it.UnitCents < 0 {
			return nil, status.Error(codes.InvalidArgument, "invalid order item")
		}
		total += int64(it.Quantity) * it.UnitCents
	}

	o.st.mu.Lock()
	defer o.st.mu.Unlock()

	if _, ok := o.st.users[req.UserId]; !ok {
		return nil, status.Error(codes.NotFound, "user not found")
	}

	id := o.st.nextID("ord", &o.st.orderSeq)
	order := &Order{
		Id:         id,
		UserId:     req.UserId,
		Items:      cloneItems(req.Items),
		Status:     "CREATED",
		TotalCents: total,
		CreatedAt:  nowUnix(),
	}
	o.st.orders[id] = order
	return &CreateOrderResponse{Order: cloneOrder(order)}, nil
}

func (o *orderService) GetOrder(ctx context.Context, req *GetOrderRequest) (*GetOrderResponse, error) {
	if strings.TrimSpace(req.Id) == "" {
		return nil, status.Error(codes.InvalidArgument, "id is required")
	}
	o.st.mu.RLock()
	defer o.st.mu.RUnlock()

	order, ok := o.st.orders[req.Id]
	if !ok {
		return nil, status.Error(codes.NotFound, "order not found")
	}
	return &GetOrderResponse{Order: cloneOrder(order)}, nil
}

func (o *orderService) ListOrders(ctx context.Context, req *ListOrdersRequest) (*ListOrdersResponse, error) {
	pageSize := int(req.PageSize)
	if pageSize <= 0 {
		pageSize = 50
	}
	if pageSize > 500 {
		pageSize = 500
	}

	offset, err := paginateTokenToOffset(req.PageToken)
	if err != nil {
		return nil, status.Error(codes.InvalidArgument, err.Error())
	}

	o.st.mu.RLock()
	defer o.st.mu.RUnlock()

	all := make([]*Order, 0, len(o.st.orders))
	for _, v := range o.st.orders {
		if req.UserId == "" || v.UserId == req.UserId {
			all = append(all, cloneOrder(v))
		}
	}

	if offset >= len(all) {
		return &ListOrdersResponse{Orders: []*Order{}, NextPageToken: ""}, nil
	}
	end := offset + pageSize
	if end > len(all) {
		end = len(all)
	}
	next := ""
	if end < len(all) {
		next = offsetToPageToken(end)
	}
	return &ListOrdersResponse{Orders: all[offset:end], NextPageToken: next}, nil
}

func (o *orderService) CancelOrder(ctx context.Context, req *CancelOrderRequest) (*CancelOrderResponse, error) {
	if strings.TrimSpace(req.Id) == "" {
		return nil, status.Error(codes.InvalidArgument, "id is required")
	}
	o.st.mu.Lock()
	defer o.st.mu.Unlock()

	order, ok := o.st.orders[req.Id]
	if !ok {
		return nil, status.Error(codes.NotFound, "order not found")
	}
	if order.Status == "CANCELLED" {
		return &CancelOrderResponse{Order: cloneOrder(order)}, nil
	}
	if order.Status == "PAID" {
		return nil, status.Error(codes.FailedPrecondition, "cannot cancel a paid order")
	}
	order.Status = "CANCELLED"
	return &CancelOrderResponse{Order: cloneOrder(order)}, nil
}

type paymentService struct{ st *store }

func (p *paymentService) CreatePayment(ctx context.Context, req *CreatePaymentRequest) (*CreatePaymentResponse, error) {
	if strings.TrimSpace(req.OrderId) == "" {
		return nil, status.Error(codes.InvalidArgument, "order_id is required")
	}
	if strings.TrimSpace(req.UserId) == "" {
		return nil, status.Error(codes.InvalidArgument, "user_id is required")
	}
	if req.AmountCents <= 0 {
		return nil, status.Error(codes.InvalidArgument, "amount_cents must be > 0")
	}

	p.st.mu.Lock()
	defer p.st.mu.Unlock()

	if _, ok := p.st.users[req.UserId]; !ok {
		return nil, status.Error(codes.NotFound, "user not found")
	}
	order, ok := p.st.orders[req.OrderId]
	if !ok {
		return nil, status.Error(codes.NotFound, "order not found")
	}
	if order.UserId != req.UserId {
		return nil, status.Error(codes.PermissionDenied, "order does not belong to user")
	}
	if order.Status == "CANCELLED" {
		return nil, status.Error(codes.FailedPrecondition, "cannot pay a cancelled order")
	}
	if req.AmountCents != order.TotalCents {
		return nil, status.Error(codes.InvalidArgument, "amount_cents must equal order total")
	}

	id := p.st.nextID("pay", &p.st.paymentSeq)
	payment := &Payment{
		Id:          id,
		OrderId:     req.OrderId,
		UserId:      req.UserId,
		AmountCents: req.AmountCents,
		Status:      "CAPTURED",
		CreatedAt:   nowUnix(),
	}
	p.st.payments[id] = payment
	order.Status = "PAID"

	return &CreatePaymentResponse{Payment: clonePayment(payment)}, nil
}

func (p *paymentService) GetPayment(ctx context.Context, req *GetPaymentRequest) (*GetPaymentResponse, error) {
	if strings.TrimSpace(req.Id) == "" {
		return nil, status.Error(codes.InvalidArgument, "id is required")
	}
	p.st.mu.RLock()
	defer p.st.mu.RUnlock()

	payment, ok := p.st.payments[req.Id]
	if !ok {
		return nil, status.Error(codes.NotFound, "payment not found")
	}
	return &GetPaymentResponse{Payment: clonePayment(payment)}, nil
}

func (p *paymentService) ListPayments(ctx context.Context, req *ListPaymentsRequest) (*ListPaymentsResponse, error) {
	pageSize := int(req.PageSize)
	if pageSize <= 0 {
		pageSize = 50
	}
	if pageSize > 500 {
		pageSize = 500
	}
	offset, err := paginateTokenToOffset(req.PageToken)
	if err != nil {
		return nil, status.Error(codes.InvalidArgument, err.Error())
	}

	p.st.mu.RLock()
	defer p.st.mu.RUnlock()

	all := make([]*Payment, 0, len(p.st.payments))
	for _, v := range p.st.payments {
		if req.UserId == "" || v.UserId == req.UserId {
			all = append(all, clonePayment(v))
		}
	}

	if offset >= len(all) {
		return &ListPaymentsResponse{Payments: []*Payment{}, NextPageToken: ""}, nil
	}
	end := offset + pageSize
	if end > len(all) {
		end = len(all)
	}
	next := ""
	if end < len(all) {
		next = offsetToPageToken(end)
	}
	return &ListPaymentsResponse{Payments: all[offset:end], NextPageToken: next}, nil
}

func (p *paymentService) RefundPayment(ctx context.Context, req *RefundPaymentRequest) (*RefundPaymentResponse, error) {
	if strings.TrimSpace(req.Id) == "" {
		return nil, status.Error(codes.InvalidArgument, "id is required")
	}

	p.st.mu.Lock()
	defer p.st.mu.Unlock()

	payment, ok := p.st.payments[req.Id]
	if !ok {
		return nil, status.Error(codes.NotFound, "payment not found")
	}
	if payment.Status == "REFUNDED" {
		return &RefundPaymentResponse{Payment: clonePayment(payment)}, nil
	}
	payment.Status = "REFUNDED"

	if order, ok := p.st.orders[payment.OrderId]; ok && order.Status == "PAID" {
		order.Status = "REFUNDED"
	}

	return &RefundPaymentResponse{Payment: clonePayment(payment)}, nil
}

func cloneUser(u *User) *User {
	if u == nil {
		return nil
	}
	cp := *u
	return &cp
}
func cloneItems(items []*OrderItem) []*OrderItem {
	out := make([]*OrderItem, 0, len(items))
	for _, it := range items {
		if it == nil {
			continue
		}
		cp := *it
		out = append(out, &cp)
	}
	return out
}
func cloneOrder(o *Order) *Order {
	if o == nil {
		return nil
	}
	cp := *o
	cp.Items = cloneItems(o.Items)
	return &cp
}
func clonePayment(p *Payment) *Payment {
	if p == nil {
		return nil
	}
	cp := *p
	return &cp
}

func main() {
	addr := flag.String("listen", ":50051", "gRPC listen address")
	flag.Parse()

	lis, err := net.Listen("tcp", *addr)
	if err != nil {
		log.Fatalf("listen: %v", err)
	}

	grpcServer := grpc.NewServer()
	st := newStore()

	RegisterUserServiceServer(grpcServer, &userService{st: st})
	RegisterOrderServiceServer(grpcServer, &orderService{st: st})
	RegisterPaymentServiceServer(grpcServer, &paymentService{st: st})

	reflection.Register(grpcServer)

	log.Printf("gRPC server listening on %s", *addr)
	if err := grpcServer.Serve(lis); err != nil {
		log.Fatalf("serve: %v", err)
	}
}